function.arguments:
{"cmd":"cd /app/ssl && {
  echo "=== Certificate Subject ==="
  openssl x509 -in server.crt -noout -subject
  echo ""
  echo "=== Certificate Validity Dates ==="
  openssl x509 -in server.crt -noout -startdate -enddate
  echo ""
  echo "=== Certificate SHA-256 Fingerprint ==="
  openssl x509 -in server.crt -noout -fingerprint -sha256
} > /app/ssl/verification.txt 2>&1 && echo "Verification file created" && cat /app/ssl/verification.txt"}
